# ---- Server ----
server <- function(input, output, session) {

  antwoorden <- reactive({
    sapply(alle_vragen$vraag_id, function(vid) {
      val <- input[[vid]]
      if (is.null(val) || val == "") NA_character_ else val
    })
  })

  ja_pct <- reactive({
    a <- antwoorden()
    round(sum(a == "Ja", na.rm = TRUE) / TOTAAL_VRAGEN * 100, 1)
  })

  output$pct_hidden <- renderText({ ja_pct() })

  output$voortgang_tekst <- renderUI({
    beantwoord <- sum(!is.na(antwoorden()))
    p(class = "voortgang-tekst",
      paste0(beantwoord, " van de ", TOTAAL_VRAGEN,
             " vragen beantwoord \u2014 ", ja_pct(), "% Ja")
    )
  })

  output$status_ui <- renderUI({
    if (ja_pct() >= DREMPEL) {
      p(class = "status-ok",
        paste0("\u2713 Voldoende Ja-antwoorden (", ja_pct(), "%) \u2014 rapport beschikbaar."))
    } else {
      nog <- DREMPEL - ja_pct()
      p(class = "status-nok",
        paste0("\u26a0 Nog ", nog, "% meer Ja nodig om het rapport te downloaden."))
    }
  })

  output$download_ui <- renderUI({
    req(ja_pct() >= DREMPEL)
    downloadButton("download_rapport", "Download rapport (HTML)", class = "shiny-download-link")
  })

  output$download_rapport <- downloadHandler(
    filename = function() {
      paste0("zzp_opdracht_checklist_", format(Sys.Date(), "%Y-%m-%d"), ".html")
    },
    content = function(file) {
      a      <- antwoorden()
      ja_n   <- sum(a == "Ja",  na.rm = TRUE)
      nee_n  <- sum(a == "Nee", na.rm = TRUE)
      leeg_n <- sum(is.na(a))
      pct    <- round(ja_n / TOTAAL_VRAGEN * 100, 1)
      datum  <- format(Sys.time(), "%d-%m-%Y %H:%M")

      # Bouw tabelrijen gegroepeerd per element
      groepen_html <- paste0(sapply(seq_along(elementen), function(ei) {
        el    <- elementen[[ei]]
        rijen <- alle_vragen[alle_vragen$element_idx == ei, ]

        # Kopregel element
        kop <- sprintf(
          "<tr>
             <td colspan='2' style='padding:10px 14px 6px;font-size:12px;font-weight:600;
               color:#1D9E75;text-transform:uppercase;letter-spacing:0.06em;
               border-top:2px solid #d0ede3;background:#f7fcfa;'>%s</td>
           </tr>",
          el$titel
        )

        # Vragen in dit element
        vraag_rijen <- paste0(sapply(seq_len(nrow(rijen)), function(ri) {
          vid <- rijen$vraag_id[ri]
          ant <- ifelse(is.na(a[vid]) | a[vid] == "", "Niet ingevuld", a[vid])
          kleur <- switch(ant,
            "Ja"  = "#1D9E75",
            "Nee" = "#D85A30",
            "#888888"
          )
          label <- switch(ant,
            "Ja"  = "\u2714 Ja",
            "Nee" = "\u2718 Nee",
            "\u2013 Niet ingevuld"
          )
          sprintf(
            "<tr>
               <td style='padding:9px 14px 9px 24px;font-size:14px;color:#222;
                 border-bottom:1px solid #f0f0f4;'>%s</td>
               <td style='padding:9px 14px;font-weight:600;font-size:14px;
                 color:%s;white-space:nowrap;border-bottom:1px solid #f0f0f4;
                 width:120px;'>%s</td>
             </tr>",
            rijen$vraag_tekst[ri], kleur, label
          )
        }), collapse = "\n")

        paste0(kop, vraag_rijen)
      }), collapse = "\n")

      html <- sprintf('<!DOCTYPE html>
<html lang="nl">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>ZZP-opdracht checklist</title>
<style>
  * { box-sizing: border-box; margin: 0; padding: 0; }
