  .page {
    max-width: 720px; margin: 40px auto; background: #fff;
    border-radius: 12px; padding: 36px 40px;
    box-shadow: 0 2px 16px rgba(0,0,0,0.09);
  }
  .pdf-knop-wrap { text-align: right; margin-bottom: 20px; }
  .pdf-knop {
    background: #1D9E75; color: #fff; border: none; border-radius: 8px;
    padding: 10px 22px; font-size: 14px; font-family: inherit;
    cursor: pointer; display: inline-flex; align-items: center; gap: 8px;
  }
  .pdf-knop:hover { background: #0F6E56; }
  .header { border-bottom: 2px solid #1D9E75; padding-bottom: 18px; margin-bottom: 28px; }
  .header h1 { font-size: 22px; color: #1a1a2e; font-weight: 600; margin-bottom: 4px; }
  .header .datum { font-size: 13px; color: #888; }
  .stats { display: flex; gap: 14px; margin-bottom: 28px; }
  .stat {
    flex: 1; background: #f0faf6; border-radius: 9px;
    padding: 14px 16px; text-align: center; border: 1px solid #c6e8d8;
  }
  .stat.warn    { background: #fff8ec; border-color: #f4d07a; }
  .stat.neutral { background: #f5f5f7; border-color: #ddd; }
  .stat-num { font-size: 28px; font-weight: 700; color: #1D9E75; }
  .stat.warn .stat-num    { color: #BA7517; }
  .stat.neutral .stat-num { color: #888; }
  .stat-lbl { font-size: 12px; color: #666; margin-top: 2px; }
  .balk-wrap { background: #e8e8ee; border-radius: 8px; height: 14px; overflow: hidden; margin-bottom: 6px; }
  .balk { height: 14px; border-radius: 8px; background: #1D9E75; width: %s%%; }
  .balk-tekst { font-size: 13px; color: #555; margin-bottom: 24px; }
  table { width: 100%%; border-collapse: collapse; }
  thead tr { background: #f0faf6; }
  thead th {
    padding: 10px 14px; font-size: 12px; color: #555;
    text-align: left; font-weight: 600;
    text-transform: uppercase; letter-spacing: 0.05em;
  }
  .footer { margin-top: 28px; font-size: 12px; color: #bbb; text-align: center; }
  @media print {
    .pdf-knop-wrap { display: none !important; }
    body { background: #fff; }
    .page { box-shadow: none; margin: 0; border-radius: 0; padding: 20px; max-width: 100%%; }
  }
</style>
</head>
<body>
<div class="page">

  <div class="pdf-knop-wrap">
    <button class="pdf-knop" onclick="window.print()">&#128438;&nbsp; Opslaan als PDF</button>
