logo_base64 <- function(bestandsnaam) {
  if (bestandsnaam == "" || !file.exists(bestandsnaam)) return(NULL)
  ext    <- tolower(tools::file_ext(bestandsnaam))
  mime   <- if (ext == "png") "image/png" else "image/jpeg"
  b64    <- base64enc::base64encode(bestandsnaam)
  paste0("data:", mime, ";base64,", b64)
