    LICHTBLAUW,             # vraagkaart bg
    BLAUW,                  # textarea focus
    GROEN,                  # status-ok kleur
    BLAUW, DONKERBLAUW      # download knop + hover
    )))
  ),

  div(class = "container-main",

    # ---- Header: titel + logo ----
    div(class = "app-header",
      h2("ZZP-opdracht checklist"),
      uiOutput("logo_ui")
    ),

    # ---- Uitlegblok ----
