server <- function(input, output, session) {

  # Logo UI
  output$logo_ui <- renderUI({
    if (LOGO_BESTAND == "" || !file.exists(LOGO_BESTAND)) return(NULL)
    # Serveer logo via addResourcePath
    tags$img(src = paste0("logo/", LOGO_BESTAND), class = "app-logo", alt = "Logo")
  })

  # Maak logo beschikbaar als statische resource
  if (LOGO_BESTAND != "" && file.exists(LOGO_BESTAND)) {
    shiny::addResourcePath("logo", dirname(normalizePath(LOGO_BESTAND)))
  }

  antwoorden <- reactive({
    sapply(alle_vragen$vraag_id, function(vid) {
      val <- input[[vid]]
      if (is.null(val) || val == "") NA_character_ else val
    })
  })

  opmerkingen <- reactive({
    # Haal opmerkingen op via JS-input; Shiny leest textarea niet automatisch,
    # dus we lezen ze via een custom input handler
    sapply(seq_len(nrow(alle_vragen)), function(i) {
      ei  <- alle_vragen$element_idx[i]
      ri  <- which(alle_vragen$element_idx == ei)[which(alle_vragen$element_idx == ei) == i - sum(alle_vragen$element_idx < ei)]
      oid <- paste0("o_", ei, "_", match(i, which(alle_vragen$element_idx == ei)))
      val <- input[[oid]]
      if (is.null(val) || trimws(val) == "") "" else trimws(val)
    })
  })

  ja_pct <- reactive({
    a <- antwoorden()
    round(sum(a == "Ja", na.rm = TRUE) / TOTAAL_VRAGEN * 100, 1)
  })

  output$pct_hidden <- renderText({ ja_pct() })

  output$voortgang_tekst <- renderUI({
    beantwoord <- sum(!is.na(antwoorden()))
    p(class = "voortgang-tekst",
      paste0(beantwoord, " van de ", TOTAAL_VRAGEN,
             " vragen beantwoord \u2014 ", ja_pct(), "% Ja")
    )
  })

  output$status_ui <- renderUI({
    pct <- ja_pct()
    if (pct >= DREMPEL) {
      p(class = "status-ok",
        paste0("\u2713 Voldoende Ja-antwoorden (", pct, "%) \u2014 rapport beschikbaar."))
    } else {
      p(class = "status-nok",
        paste0("\u26a0 ", pct, "% Ja \u2014 rapport beschikbaar, maar percentage is onder de drempel van ", DREMPEL, "%."))
    }
  })

  # Download altijd beschikbaar
  output$download_ui <- renderUI({
    downloadButton("download_rapport", "Download rapport (HTML)", class = "shiny-download-link")
  })

  output$download_rapport <- downloadHandler(
    filename = function() {
      paste0("zzp_checklist_", format(Sys.Date(), "%Y-%m-%d"), ".html")
    },
    content = function(file) {
      a      <- antwoorden()
      ja_n   <- sum(a == "Ja",  na.rm = TRUE)
      nee_n  <- sum(a == "Nee", na.rm = TRUE)
      leeg_n <- sum(is.na(a))
      pct    <- round(ja_n / TOTAAL_VRAGEN * 100, 1)
      datum  <- format(Sys.time(), "%d-%m-%Y %H:%M")

      # Kleur percentage: rood onder drempel, groen erboven
      pct_kleur <- if (pct >= DREMPEL) GROEN else ROOD

      # Logo als base64 inbedden (werkt ook als los bestand geopend wordt)
      logo_src <- logo_base64(LOGO_BESTAND)
      logo_html <- if (!is.null(logo_src)) {
        sprintf("<img src='%s' style='max-height:56px;max-width:180px;object-fit:contain;' alt='Logo'>", logo_src)
      } else ""

      # Opmerking per vraag ophalen
      alle_opmerkingen <- sapply(seq_len(nrow(alle_vragen)), function(i) {
        ei  <- alle_vragen$element_idx[i]
        ri  <- match(i, which(alle_vragen$element_idx == ei))
        oid <- paste0("o_", ei, "_", ri)
        val <- input[[oid]]
        if (is.null(val) || trimws(val) == "") "" else trimws(val)
      })

      # Tabelrijen gegroepeerd per element
      groepen_html <- paste0(sapply(seq_along(elementen), function(ei) {
        el    <- elementen[[ei]]
        rijen <- alle_vragen[alle_vragen$element_idx == ei, ]

        kop <- sprintf(
          "<tr><td colspan='3' style='padding:10px 14px 6px 14px;font-size:11px;font-weight:700;
            color:%s;text-transform:uppercase;letter-spacing:0.07em;
            border-top:2px solid %s;background:%s;'>%s</td></tr>",
          BLAUW, LICHTBLAUW, LICHTBLAUW, el$titel
        )

        vraag_rijen <- paste0(sapply(seq_len(nrow(rijen)), function(ri) {
          i_global <- which(alle_vragen$vraag_id == rijen$vraag_id[ri])
          vid <- rijen$vraag_id[ri]
          ant <- ifelse(is.na(a[vid]) | a[vid] == "", "Niet ingevuld", a[vid])
          opmerking <- alle_opmerkingen[i_global]

          ant_kleur <- switch(ant,
            "Ja"  = GROEN,
            "Nee" = ROOD,
            "#888888"
          )
          ant_label <- switch(ant,
            "Ja"  = "\u2714 Ja",
            "Nee" = "\u2718 Nee",
            "\u2013 Niet ingevuld"
          )
          opmerking_html <- if (opmerking != "") {
            sprintf("<div style='font-size:12px;color:#666;margin-top:5px;
              font-style:italic;padding-left:2px;'>&#128172; %s</div>", opmerking)
          } else ""

          sprintf(
            "<tr>
               <td style='padding:10px 14px 10px 22px;font-size:14px;color:#222;
                 border-bottom:1px solid #eaecf4;vertical-align:top;'>
                 %s%s
               </td>
               <td style='padding:10px 14px;font-weight:700;font-size:14px;
                 color:%s;white-space:nowrap;border-bottom:1px solid #eaecf4;
                 width:110px;vertical-align:top;'>%s</td>
             </tr>",
            rijen$vraag_tekst[ri], opmerking_html, ant_kleur, ant_label
          )
        }), collapse = "\n")

        paste0(kop, vraag_rijen)
      }), collapse = "\n")

      html <- sprintf('<!DOCTYPE html>
<html lang="nl">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>ZZP-opdracht checklist</title>
<link href="https://fonts.googleapis.com/css2?family=Nunito:wght@300;400;600;700;900&display=swap" rel="stylesheet">
<style>
  * { box-sizing: border-box; margin: 0; padding: 0; }
  body { font-family: "Nunito", "Segoe UI", Arial, sans-serif; background: #f4f6fb; color: #222; }
  .page {
    max-width: 740px; margin: 36px auto; background: #fff;
    border-radius: 14px; padding: 36px 42px;
    box-shadow: 0 2px 18px rgba(86,106,176,0.10);
  }
  .rapport-header {
    display: flex; align-items: center; justify-content: space-between;
    border-bottom: 2px solid %s; padding-bottom: 18px; margin-bottom: 26px;
  }
  .rapport-header h1 { font-size: 21px; color: %s; font-weight: 700; margin-bottom: 3px; }
  .rapport-header .datum { font-size: 12px; color: #999; }
  .stats { display: flex; gap: 12px; margin-bottom: 26px; }
  .stat {
    flex: 1; border-radius: 10px; padding: 14px 12px;
    text-align: center; border: 1px solid #c5cee0; background: %s;
  }
  .stat.warn    { background: #fff8ec; border-color: #f4d07a; }
  .stat.neutral { background: #f5f5f7; border-color: #ddd; }
  .stat-num { font-size: 26px; font-weight: 900; color: %s; }
  .stat-num.rood { color: %s; }
  .stat.warn .stat-num    { color: #BA7517; }
  .stat.neutral .stat-num { color: #888; }
  .stat-lbl { font-size: 11px; color: #666; margin-top: 2px; font-weight: 600; text-transform: uppercase; letter-spacing: 0.05em; }
  .balk-wrap { background: #dde3f0; border-radius: 8px; height: 13px; overflow: hidden; margin-bottom: 5px; }
  .balk { height: 13px; border-radius: 8px; background: %s; width: %s%%; }
  .balk-tekst { font-size: 12px; color: #777; margin-bottom: 24px; }
  .pdf-knop-wrap { text-align: right; margin-bottom: 22px; }
  .pdf-knop {
    background: %s; color: #fff; border: none; border-radius: 9px;
    padding: 10px 22px; font-size: 14px; font-weight: 700;
    font-family: inherit; cursor: pointer;
    display: inline-flex; align-items: center; gap: 7px;
  }
  .pdf-knop:hover { background: %s; }
  table { width: 100%%; border-collapse: collapse; }
  thead tr { background: %s; }
  thead th {
    padding: 10px 14px; font-size: 11px; color: %s;
    text-align: left; font-weight: 700;
    text-transform: uppercase; letter-spacing: 0.06em;
  }
  .footer { margin-top: 26px; font-size: 11px; color: #bbb; text-align: center; }
  @media print {
    .pdf-knop-wrap { display: none !important; }
    body { background: #fff; }
    .page { box-shadow: none; margin: 0; border-radius: 0; padding: 20px; max-width: 100%%; }
  }
</style>
</head>
<body>
<div class="page">

  <div class="pdf-knop-wrap">
    <button class="pdf-knop" onclick="window.print()">&#128438;&nbsp; Opslaan als PDF</button>
  </div>

  <div class="rapport-header">
    <div>
