      <div class="stat-lbl">Niet ingevuld</div>
    </div>
  </div>

  <div class="balk-wrap"><div class="balk"></div></div>
  <div class="balk-tekst">%s%% van de vragen beantwoord met Ja (drempel: %d%%)</div>

  <table>
    <thead>
      <tr>
        <th>Stelling / opmerking</th>
        <th style="width:110px;">Antwoord</th>
      </tr>
    </thead>
    <tbody>
      %s
    </tbody>
  </table>

  <div class="footer">%s &middot; ZZP-opdracht checklist &middot; automatisch gegenereerd &middot; %s</div>
</div>
</body>
</html>',
        # CSS variabelen invullen
        BLAUW, BLAUW,                          # header border + h1
        LICHTBLAUW,                            # stat bg
        GROEN, ROOD,                           # stat-num groen + rood class
        pct_kleur, pct,                        # balk kleur + breedte
        BLAUW, DONKERBLAUW,                    # pdf-knop + hover
        LICHTBLAUW, BLAUW,                     # thead bg + th kleur
        # Inhoud
        datum,                                 # datum
        logo_html,                             # logo
        if (pct < DREMPEL) "rood" else "", pct, # pct kleur class + waarde
        ja_n, nee_n, leeg_n,                   # stat nummers
        pct, DREMPEL,                          # balk tekst
        groepen_html,                          # tabel
        ORG_NAAM, datum                        # footer
      )

      writeLines(html, file)
    }
  )
}

