logo_base64_string <- NULL

if (LOGO_BESTAND != "" && file.exists(LOGO_BESTAND)) {
  ext  <- tolower(tools::file_ext(LOGO_BESTAND))
  mime <- switch(ext,
                 "png"  = "image/png",
                 "jpg"  = "image/jpeg",
                 "jpeg" = "image/jpeg",
                 "webp" = "image/webp",
                 "svg"  = "image/svg+xml",
                 "image/png"
  )
  b64 <- base64enc::base64encode(LOGO_BESTAND)
  logo_base64_string <- paste0("data:", mime, ";base64,", b64)
} else if (LOGO_BESTAND != "") {
  warning(paste0(
    "Logo niet gevonden: '", LOGO_BESTAND, "'\n",
