        </td>
      </tr>",
            waarschuwingen[[el$titel]]
          )
        }
        
        extra_html <- ""
        if (ei == 5 && sum(antwoorden_vec == "Nee", na.rm = TRUE) >= 2) {
          extra_html <- "
