  %s
</td>

      </tr>",
            rijen$vraag_tekst[ri], opmerking_html, ant_kleur, ant_label, waarschuwing_check
          )
        }), collapse = "\n")
        
        paste0(kop, vraag_rijen)
        
      }), collapse = "\n")
      
      html <- sprintf('<!DOCTYPE html>
