library(shiny)

# ---- Pas hier je vragen aan --------------------------------
vragen <- c(
  "Heeft u een geldige verzekeringspolis?",
  "Is de premiebetaling up-to-date?",
  "Zijn alle verzekerden correct geregistreerd?",
  "Is het eigen risico acceptabel voor u?",
  "Heeft u de polisvoorwaarden gelezen?",
  "Zijn de dekkingen volledig voor uw situatie?",
  "Is de looptijd van de polis correct?",
  "Heeft u een kopie van de polis ontvangen?"
)

DREMPEL <- 70  # minimaal percentage Ja voor download

# ---- UI ----------------------------------------------------
ui <- fluidPage(
  tags$head(tags$style(HTML("
    body { font-family: Arial, sans-serif; background: #f5f5f5; }
    .container { max-width: 700px; margin: 30px auto; background: white;
                 padding: 30px; border-radius: 8px; box-shadow: 0 2px 8px rgba(0,0,0,0.1); }
    .vraag-blok { padding: 12px 16px; margin-bottom: 8px; border-radius: 6px;
                  border: 1px solid #e0e0e0; background: #fafafa; }
    .voortgang { font-size: 18px; font-weight: bold; margin: 20px 0 5px; }
    .balk-bg { background: #e0e0e0; border-radius: 10px; height: 14px; margin-bottom: 6px; }
    .balk-vul { height: 14px; border-radius: 10px; transition: width 0.3s; }
    .info-tekst { color: #666; font-size: 14px; margin-bottom: 20px; }
    .download-sectie { margin-top: 24px; padding-top: 20px; border-top: 1px solid #eee; }
  "))),

  div(class = "container",
    h2("Checklist vragenlijst"),
    p("Beantwoord alle vragen met Ja of Nee. Bij 70% of meer Ja kunt u het PDF-rapport downloaden."),

    # Voortgangsbalk
    div(class = "voortgang", textOutput("pct_tekst")),
    div(class = "balk-bg",
      div(class = "balk-vul", style = "background:#2196F3;",
        uiOutput("balk_breedte")
      )
    ),
    p(class = "info-tekst", textOutput("status_tekst")),

    # Vragen
    div(
      lapply(seq_along(vragen), function(i) {
        div(class = "vraag-blok",
          radioButtons(
            inputId  = paste0("v", i),
            label    = paste0(i, ". ", vragen[i]),
            choices  = c("Ja", "Nee"),
            selected = character(0),
            inline   = TRUE
          )
        )
      })
    ),

    # Download sectie
    div(class = "download-sectie",
      uiOutput("download_ui")
    )
  )
)

# ---- Server ------------------------------------------------
server <- function(input, output, session) {

  # Bereken hoeveel procent Ja is ingevuld
  ja_pct <- reactive({
    antwoorden <- sapply(seq_along(vragen), function(i) input[[paste0("v", i)]])
    ja_count   <- sum(antwoorden == "Ja", na.rm = TRUE)
    round(ja_count / length(vragen) * 100, 1)
  })

  # Aantal nog niet beantwoord
  open_count <- reactive({
    sum(sapply(seq_along(vragen), function(i) is.null(input[[paste0("v", i)]]) || input[[paste0("v", i)]] == ""))
  })

  output$pct_tekst <- renderText({
    paste0("Ja-percentage: ", ja_pct(), "%")
  })

  output$status_tekst <- renderText({
    if (ja_pct() >= DREMPEL && open_count() == 0) {
      "Voldoende Ja antwoorden — download beschikbaar!"
    } else if (ja_pct() >= DREMPEL) {
      paste0("Genoeg Ja, maar nog ", open_count(), " vragen niet beantwoord.")
    } else {
      paste0("Nog ", DREMPEL - ja_pct(), "% meer Ja nodig voor download.")
    }
  })

  # Voortgangsbalk breedte via inline style
  output$balk_breedte <- renderUI({
    kleur <- if (ja_pct() >= DREMPEL) "#4CAF50" else if (ja_pct() >= 40) "#FF9800" else "#f44336"
    tags$div(style = paste0(
      "height:14px; border-radius:10px; width:", ja_pct(), "%;",
      "background:", kleur, "; transition: width 0.3s;"
    ))
  })

  # Download knop alleen zichtbaar bij >= 70% ja
  output$download_ui <- renderUI({
    if (ja_pct() >= DREMPEL) {
      downloadButton("download_pdf", "Download PDF rapport", class = "btn btn-success btn-lg")
    } else {
      tags$p(
        tags$span(style = "color:#999;",
          paste0("Download beschikbaar zodra u ", DREMPEL, "% of meer Ja heeft.")
        )
      )
    }
  })

  # PDF genereren via R Markdown
  output$download_pdf <- downloadHandler(
    filename = function() {
      paste0("checklist_rapport_", format(Sys.Date(), "%Y-%m-%d"), ".pdf")
    },
    content = function(file) {
      antwoorden <- sapply(seq_along(vragen), function(i) input[[paste0("v", i)]])
      resultaten_df <- data.frame(
        Nr       = seq_along(vragen),
        Vraag    = vragen,
        Antwoord = antwoorden,
        stringsAsFactors = FALSE
      )

      # Kopieer template naar tijdelijke map (vereist door rmarkdown)
      tmpdir       <- tempdir()
      temp_rmd     <- file.path(tmpdir, "rapport.Rmd")
      file.copy("rapport_template.Rmd", temp_rmd, overwrite = TRUE)

      # Render PDF
      rmarkdown::render(
        input       = temp_rmd,
        output_file = file,
        params = list(
          resultaten_df = resultaten_df,
          ja_pct        = ja_pct(),
          datum         = format(Sys.time(), "%d-%m-%Y om %H:%M")
        ),
        envir = new.env(parent = globalenv())
      )
    }
  )
}

