   </div>",
        ifelse(is.null(naam) || naam == "", "-", naam),
        ifelse(is.null(aandacht) || aandacht == "", "-", gsub("\n", "<br>", aandacht))
      )
      pct_kleur <- if (pct <= 50) {
        ROOD
      } else if (pct <= 65) {
        "#f39c12"   # oranje
      } else {
        GROEN
      }
     
      
      # Logo HTML voor rapport (base64 al ingelezen bij opstarten)
